SELECT total_emissions
FROM food_system_data
WHERE sector = 'Energy' AND country_code_a3 = 'AGO';

SELECT SUM(total_emissions) AS total_emissions_2022
FROM food_system_data
WHERE year = 2022;

SELECT country_code_a3, year, SUM(total_emissions) AS total_emissions_sum
FROM food_system_data
GROUP BY country_code_a3, year;

SELECT name
FROM countries
WHERE country_code_a3 = 'AFG';
